#include <stdio.h>
#include <math.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    for (int i = 0; i < Q; i++) {
        int L, R, D;
        scanf("%d %d %d", &L, &R, &D);
        if (D == 0) {
            double sum = 0;
            for (int j = L; j <= R; j++) {
                sum += sin(j);
            }
            printf("%.6f\n", sum);
        } else {
            // We don't need to do anything here because we are not storing the numbers
        }
    }
    return 0;
}

